function LxResPathUtil.GetEffectPath(effectName)
	if (not string.isempty(effectName)) then
		effectName = gLGameLanguage:GetResName(effectName)

		local effectPath = GameTable.AutoEffectRef[string.lower(effectName)]
		if (effectPath) then
			return effectPath
		end
		if LOG_INFO_ENABLED then
			printErrorN("GameTable.AutoEffectRef Lost | " .. effectName)
		end
	end
	return nil
end

function LxResPathUtil.GetEffectAssetPath(effectName)
	local pathName = LxResPathUtil.GetEffectPath(effectName)
	if(string.isempty(pathName)) then
		return effectName
	end
	local assetPath = pathName .. "/" .. effectName
	return assetPath
end

function LxResPathUtil.GetAudioFullPath(audioName)
	if (not string.isempty(audioName)) then
		audioName = gLGameLanguage:GetAudioName(audioName)

		local audioPath = GameTable.AutoAudioRef[string.lower(audioName)]
		if (audioPath) then
			return audioPath.."/"..audioName
		end
		if LOG_INFO_ENABLED then
			printErrorN("GameTable.AutoAudioRef Lost | " .. audioName)
		end
	end
	return nil
end

function LxResPathUtil.GetSpritePath(assetName)
	local assetPath = GameTable.AutoAtlasRef[string.lower(assetName)]
	if (not assetPath) then
		if LOG_INFO_ENABLED then
			printErrorN("GameTable.AutoAtlasRef Lost | " .. assetName)
		end
		return nil
	end
	return assetPath.."/"..assetName
end

function LxResPathUtil.GetSpriteAtlasPath(assetName)
	if string.isempty(assetName) then return nil end

	local assetPath = GameTable.AutoAtlasRef[string.lower(assetName)]
	if (not assetPath) then
		if LOG_INFO_ENABLED then
			printErrorN("GameTable.AutoAtlasRef Lost | " .. assetName)
		end
		return nil
	end

	local isSingle = string.find(string.lower(assetPath), '/zsingle')
	local atlasName = string.gsub(assetPath, "/", "_")
	if isSingle then
		assetName = string.format("%s_%s.spriteatlasv2", atlasName, assetName)
	else
		assetName = string.format("%s.spriteatlasv2", atlasName)
	end
	atlasName = string.lower(assetName)
	return atlasName
end

function LxResPathUtil.GetAudioSoundName(transName, soundRefId)
	if soundRefId == nil then
		local name = string.lower(transName)
		local nameToSound = LxResPathUtil._nameToSound
		if not nameToSound then
			nameToSound = {
				["closebtn"] = LSoundConst.CLICK_CLOSE_COMMON,
				["backbtn"] = LSoundConst.CLICK_CLOSE_COMMON,
				["quitbtn"] = LSoundConst.CLICK_CLOSE_COMMON,
				["exitbtn"] = LSoundConst.CLICK_CLOSE_COMMON,
				["returnbtn"] = LSoundConst.CLICK_CLOSE_COMMON,
				["btnclose"] = LSoundConst.CLICK_CLOSE_COMMON,
				["mask"] = LSoundConst.CLICK_CLOSE_COMMON,
				["helpbtn"] = LSoundConst.CLICK_ERROR_COMMON,
				["cityimage"] = LSoundConst.CLICK_MAINBTN_CITY,
				["heroimage"] = LSoundConst.CLICK_MAINBTN_HERO,
				["fightimage"] = LSoundConst.CLICK_MAINBTN_ADVENTURE,
				["guildimage"] = LSoundConst.CLICK_MAINBTN_SUBURB,
			}
			LxResPathUtil.nameToSound = nameToSound
		end
		soundRefId  = nameToSound[name] or LSoundConst.CLICK_BUTTON_COMMON


	end
	soundRefId = tonumber(soundRefId) or 0
	if soundRefId <= 0 then
		return
	end
	return LxResPathUtil.GetAudioSoundNameByRefId(soundRefId)
end

function LxResPathUtil.GetAudioSoundNameByRefId(soundRefId)

	local ref = GameTable.SoundEffectRef[soundRefId]
	if ref then
		return ref.soundName
	end
end

