function LxResPathUtil.GetAutoSpineRef(spineName)
	return GameTable.AutoSpineRef[spineName]
end

function LxResPathUtil.GetSpineAniTime(spineName, aniName, defaultVal)
	local ref = GameTable.AutoSpineRef[spineName]
	if ref then
		if not ref[aniName] then
			if LOG_INFO_ENABLED then
				printErrorN2("spine相关",string.replace("#a1# 的 #a2# 动画缺失",spineName,aniName))
			end
		end
		return ref[aniName] or 0
	end
	return defaultVal
end

